func solve(n: Int64, k: Int64) -> Int64 {
    let k_val = Int(k)
    if k_val == 0 {
        return 1
    }

    var dep = [Int](repeating: 0, count: 61)
    dep[1] = 0
    if 2 <= 60 {
        for i in 2...60 {
            let p = i.nonzeroBitCount
            dep[i] = 1 + dep[p]
        }
    }

    let targetDepth = k_val - 1
    var S = Set<Int>()
    for s in 1...60 {
        if dep[s] == targetDepth {
            S.insert(s)
        }
    }

    if S.isEmpty {
        if k_val == 1 {
            return -1
        } else {
            return 0
        }
    }

    let s_binary = String(n, radix: 2)
    let L = s_binary.count
    var memo: [ (Int, Bool, Int) : Int64 ] = [:]

    func dfs(_ pos: Int, _ tight: Bool, _ count: Int) -> Int64 {
        if pos == L {
            if S.contains(count) {
                return 1
            } else {
                return 0
            }
        }
        let key = (pos, tight, count)
        if let val = memo[key] {
            return val
        }
        var total: Int64 = 0
        let currentChar = s_binary[s_binary.index(s_binary.startIndex, offsetBy: pos)]
        let upperBound: Int
        if tight {
            upperBound = (currentChar == "1") ? 1 : 0
        } else {
            upperBound = 1
        }
        for bit in 0...upperBound {
            let new_tight = tight && (bit == upperBound)
            let new_count = count + (bit == 1 ? 1 : 0)
            total += dfs(pos + 1, new_tight, new_count)
        }
        memo[key] = total
        return total
    }

    let totalInclusive = dfs(0, true, 0)
    if k_val == 1 {
        return totalInclusive - 1
    } else {
        return totalInclusive
    }
}
```

