func solve(n: Int64, k: Int64) -> Int64 {
    if k == 0 {
        return n >= 1 ? 1 : 0
    }

    let M = 70
    var dep = [Int](repeating: 0, count: M+1)
    dep[1] = 0
    for i in 2...M {
        var count = 0
        var x = i
        while x != 0 {
            count += 1
            x = x & (x - 1)
        }
        dep[i] = 1 + dep[count]
    }

    func getBinaryDigits(_ n: Int64) -> [Int] {
        if n == 0 {
            return [0]
        }
        var x = n
        var bits = [Int]()
        while x > 0 {
            bits.insert(Int(x & 1), at: 0)
            x = x >> 1
        }
        return bits
    }

    func countNumbers(n: Int64, bits c: Int) -> Int64 {
        if c < 0 {
            return 0
        }
        if n == 0 {
            return 0
        }
        let digits = getBinaryDigits(n)
        let L = digits.count
        var dp0 = [Int64](repeating: 0, count: c+1)
        var dp1 = [Int64](repeating: 0, count: c+1)
        dp1[0] = 1

        for i in 0..<L {
            let current_bit = digits[i]
            var new_dp0 = [Int64](repeating: 0, count: c+1)
            var new_dp1 = [Int64](repeating: 0, count: c+1)

            for count_val in 0...c {
                let val0 = dp0[count_val]
                if val0 > 0 {
                    for d in [0, 1] {
                        let new_count = count_val + (d == 1 ? 1 : 0)
                        if new_count <= c {
                            new_dp0[new_count] += val0
                        }
                    }
                }

                let val1 = dp1[count_val]
                if val1 > 0 {
                    for d in 0...current_bit {
                        let new_count = count_val + (d == 1 ? 1 : 0)
                        if new_count > c {
                            continue
                        }
                        if d == current_bit {
                            new_dp1[new_count] += val1
                        } else {
                            new_dp0[new_count] += val1
                        }
                    }
                }
            }

            dp0 = new_dp0
            dp1 = new_dp1
        }

        return dp0[c] + dp1[c]
    }

    var total: Int64 = 0
    for i in 1...M {
        if dep[i] == (k - 1) {
            total += countNumbers(n: n, bits: i)
        }
    }

    if k == 1 && n >= 1 {
        total -= 1
    }

    return total
}
