func solve(n: Int64, k: Int64) -> Int64 {
    if k == 0 {
        return 1
    }
    let T = Int(k) - 1
    var depth_table = [Int](repeating: -1, count: 61)
    depth_table[1] = 0
    func popcount(_ x: Int) -> Int {
        var y = x
        var cnt = 0
        while y > 0 {
            cnt += y & 1
            y >>= 1
        }
        return cnt
    }
    for i in 2..<61 {
        let pc = popcount(i)
        depth_table[i] = 1 + depth_table[pc]
    }
    var bits = [Int]()
    var num = n
    while num > 0 {
        bits.append((num & 1) == 1 ? 1 : 0)
        num = num >> 1
    }
    bits.reverse()
    let L = bits.count
    var dp = [[[Int64]]](repeating: [[Int64]](repeating: [0, 0], count: L+1), count: L+1)
    dp[0][0][1] = 1
    for i in 0..<L {
        for j in 0...L {
            for t in 0...1 {
                let current = dp[i][j][t]
                if current == 0 { continue }
                let low = 0
                let high = t == 1 ? bits[i] : 1
                for d in low...high {
                    let new_t: Int = (t == 1 && d == bits[i]) ? 1 : 0
                    let new_j = j + (d == 1 ? 1 : 0)
                    if new_j <= L {
                        dp[i+1][new_j][new_t] += current
                    }
                }
            }
        }
    }
    var counts = [Int64](repeating: 0, count: L+1)
    for j in 0...L {
        counts[j] = dp[L][j][0] + dp[L][j][1]
    }
    var ans: Int64 = 0
    for y in 1..<61 {
        if y > L { continue }
        if depth_table[y] == T {
            var c = counts[y]
            if y == 1 {
                c = max(0, c - 1)
            }
            ans += c
        }
    }
    return ans
}
