func count_popcount(t: Int, n: Int64) -> Int64 {
    if n == 0 {
        return 0
    }
    var num = n
    var bits = [Int]()
    while num != 0 {
        bits.append(Int(num & 1))
        num >>= 1
    }
    bits.reverse()
    let L = bits.count
    var dp = [[[[Int64]]]](repeating: [[[Int64]]](repeating: [[Int64]](repeating: [Int64](repeating: 0, count: t+1), count: 2), count: 2), count: L+1)
    dp[0][1][0][0] = 1
    for i in 0..<L {
        for tight in 0...1 {
            for started in 0...1 {
                for count in 0...t {
                    let current = dp[i][tight][started][count]
                    if current == 0 {
                        continue
                    }
                    let low = 0
                    let high = (tight == 1) ? bits[i] : 1
                    for d in low...high {
                        let newTight = (tight == 1) ? (d == bits[i] ? 1 : 0) : 0
                        var newStarted = started
                        var newCount = count
                        if started == 0 && d == 0 {
                        } else {
                            newStarted = 1
